// Generates components/terminal/xterm-bundle.ts by inlining the xterm.js dist
// JS/CSS that the terminal WebView used to load from a CDN. Run after bumping
// @xterm/xterm or @xterm/addon-fit:
//
//   pnpm --dir apps/mobile run bundle:xterm
//
// The emitted file is committed so the terminal renders offline / with the CDN
// blocked. Versions are read from the installed packages so the generated file
// and package.json can never drift.
import { createRequire } from "node:module";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";
import { mkdirSync, readFileSync, writeFileSync } from "node:fs";

const require = createRequire(import.meta.url);
const here = dirname(fileURLToPath(import.meta.url));

function readDist(pkg, ...relParts) {
  // Resolve via package.json (always exported) then read the dist file directly,
  // so an `exports` map on the package cannot block the deep lib/css paths.
  const pkgJsonPath = require.resolve(`${pkg}/package.json`);
  const pkgDir = dirname(pkgJsonPath);
  const version = JSON.parse(readFileSync(pkgJsonPath, "utf8")).version;
  const contents = readFileSync(join(pkgDir, ...relParts), "utf8");
  return { version, contents };
}

const xtermJs = readDist("@xterm/xterm", "lib", "xterm.js");
const xtermCss = readDist("@xterm/xterm", "css", "xterm.css");
const fitJs = readDist("@xterm/addon-fit", "lib", "addon-fit.js");

const out = `// @generated by scripts/bundle-xterm.mjs — DO NOT EDIT BY HAND.
// Inlined @xterm/xterm ${xtermJs.version} + @xterm/addon-fit ${fitJs.version}
// dist so the terminal WebView renders without a CDN. Regenerate with
// \`pnpm --dir apps/mobile run bundle:xterm\` after bumping either package.
// (eslint-ignored via eslint.config.js — this is a vendored dist.)
export const XTERM_VERSION = ${JSON.stringify(xtermJs.version)};
export const FIT_ADDON_VERSION = ${JSON.stringify(fitJs.version)};
export const XTERM_CSS = ${JSON.stringify(xtermCss.contents)};
export const XTERM_JS = ${JSON.stringify(xtermJs.contents)};
export const FIT_ADDON_JS = ${JSON.stringify(fitJs.contents)};
`;

const target = join(here, "..", "components", "terminal", "xterm-bundle.ts");
mkdirSync(dirname(target), { recursive: true });
writeFileSync(target, out);

const kb = (s) => Math.round(s.length / 1024);
console.log(
  `Wrote ${target}\n  xterm ${xtermJs.version} (${kb(xtermJs.contents)} KB js, ${kb(xtermCss.contents)} KB css)\n  addon-fit ${fitJs.version} (${kb(fitJs.contents)} KB js)`,
);
